import { faGithub } from '@fortawesome/free-brands-svg-icons';
import React from 'react'
import { Container, Row, Col, Button } from 'shards-react';
import Icon from './icon';

export default function Project (props) {
    return(
        <div className="project outline">
            <h3>{props.title}</h3>
            <p>{props.des}</p>
            <Row>
                <Col md="3" xs="4">{props.date}</Col>
                <Col md="2" xs="4">{props.cat}</Col>
                <Col md="3" xs="4">{props.company}</Col>
                <Col md="4" xs="10">
                    {
                        props.github &&
                        <a href={props.github} target="blank">
                            <Icon id="github" onlyIcon={true} icon={faGithub}/>
                        </a>
                    }
                    {
                        props.website && 
                        <a href={props.website} target="blank">
                            <Button theme="danger" style={{backgroundColor: 'var(--accent-colour)'}}>Visit Site</Button>
                        </a> 
                    }
                </Col>
            </Row>
        </div>
    )
}