import React from 'react'
import { Nav, NavbarBrand, NavItem, NavLink } from "shards-react"
import AnchorLink from 'react-anchor-link-smooth-scroll'

function NavBar(props) {
    return (
        <Nav pills className="main">
            <NavItem>
                {props.page ==='about' ? <NavLink active href="/portfolio/"> About </NavLink> : <NavLink href="/portfolio/"> About </NavLink>}
            </NavItem>
            <NavItem>
                {props.page ==='work' ? <NavLink active href="/portfolio/work"> Works </NavLink> : <NavLink href="/portfolio/work"> Works </NavLink>}
            </NavItem>
            <NavItem>
                <AnchorLink className="nav-link" href="#footer">
                    {/* <NavLink href="#footer"> */}
                        Contact
                    {/* </NavLink> */}
                </AnchorLink>
            </NavItem>
            <NavbarBrand >
                <img style={{height: '5vh'}} src={require('../images/logo.png')} alt="personal logo"/>
            </NavbarBrand>
        </Nav>
    );
}

export default NavBar
