import React from 'react'
import { Container, Row, Col } from 'shards-react'
import Icon from './icon'

export default function SkillSection(props) {
    const title = <Col md="4">
        <h1>{props.title.split('_').join(' ')}</h1>
    </Col>

    const list = <Col md="7">
                    <Row>
                    {props.skills.map(s => {
                        return <Icon key={s.name} id={s.name} msg={s.des} icon={s.icon} align={false}/>
                    })}
                    </Row>
                </Col>
    return(
        <Container className="skill-section">
            <Row>
                {props.dir === 0 && window.innerHeight < window.innerWidth ? title :
                window.innerHeight > window.innerWidth ? title : list}
                <Col md="1"/>
                {props.dir === 1 && window.innerHeight < window.innerWidth ? title : list}
                {/* {window.innerHeight > window.innerWidth && list} */}
            </Row>
        </Container>
    )
}