import React, { useState } from 'react'
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { Col, Tooltip } from 'shards-react';

export default function Icon(props) {
    let [toggleTip, setToggleTip] = useState(false);
    const id = props.id.replace('/','').split(' ').join('');
    function toggle(){
        setToggleTip(!toggleTip)
    }

    if(props.onlyIcon){
        return(
            <Col>
                <div className='icon' style={{backgroundColor: 'var(--accent-colour)'}}>
                    <FontAwesomeIcon icon={props.icon}/>
                </div>
            </Col>
        )
    } else {
        return(
            <Col xs={!props.align ? '4' : ''} className={!props.align ? 'skill' : ''}>
                <div className={props.align ? 'icon' : 'icon-large'} id={id} style={{margin: props.align ? 'auto' : 'initial'}}>
                    <FontAwesomeIcon icon={props.icon}/>
                </div>
                {props.des && <Tooltip open={toggleTip} target={'#' + id} toggle={toggle}>
                    {props.msg}
                </Tooltip>}
                {props.align && <p className="icon-caption-bot">{props.id}</p>}
                {!props.align && <h3 className="icon-caption-right">{props.id}</h3>}
            </Col>
        )
    }
}